# @cctt_verify {"v":2,"sym":"sympy.assumptions.tests.test_query.test_key_extensibility","kind":"function","src_hash":"9f08a95c9e3427ea","in":{"base":"Any"},"out":{"base":"Any","pred":"ask(Q.my_key(x)) is True and ask(Q.my_key(x + 1)) is None and ask(Q.my_key(x)) is True and ask(Q.my_key(x + 1)) is None"},"spec":{"lhs":"test_key_extensibility()","rhs":"test that you can add keys to the ask system at runtime","over":{"base":"Any"},"name":"test_key_extensibility_correct"},"guarantee":"test that you can add keys to the ask system at runtime","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.assumptions.tests.test_query.test_key_extensibility_correct","statement":"Path(test_key_extensibility(x), test that you can add keys to the ask system at runtime)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"3949623d8138fc49"}
def test_key_extensibility():
    """test that you can add keys to the ask system at runtime"""
    # make sure the key is not defined
    raises(AttributeError, lambda: ask(Q.my_key(x)))

    # Old handler system
    class MyAskHandler(AskHandler):
        @staticmethod
        def Symbol(expr, assumptions):
            return True
    try:
        with warns_deprecated_sympy():
            register_handler('my_key', MyAskHandler)
        with warns_deprecated_sympy():
            assert ask(Q.my_key(x)) is True
        with warns_deprecated_sympy():
            assert ask(Q.my_key(x + 1)) is None
    finally:
        # We have to disable the stacklevel testing here because this raises
        # the warning twice from two different places
        with warns_deprecated_sympy():
            remove_handler('my_key', MyAskHandler)
        del Q.my_key
    raises(AttributeError, lambda: ask(Q.my_key(x)))

    # New handler system
    class MyPredicate(Predicate):
        pass
    try:
        Q.my_key = MyPredicate()
        @Q.my_key.register(Symbol)
        def _(expr, assumptions):
            return True
        assert ask(Q.my_key(x)) is True
        assert ask(Q.my_key(x+1)) is None
    finally:
        del Q.my_key
    raises(AttributeError, lambda: ask(Q.my_key(x)))


