# @cctt_verify {"v":2,"sym":"sympy.assumptions.tests.test_query.test_custom_AskHandler","kind":"function","src_hash":"4949d56ee367dc4d","in":{"base":"Any"},"out":{"base":"Any","pred":"ask(Q.mersenne(7)) and ask(Q.mersenne(n), Q.mersenne(n)) and ask(Q.mersenne(7)) and ask(Q.mersenne(n), Q.mersenne(n))"},"spec":{"lhs":"test_custom_AskHandler()","rhs":"test_custom_AskHandler produces the expected output","over":{"base":"Any"},"name":"test_custom_AskHandler_correct"},"guarantee":"test_custom_AskHandler produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.assumptions.tests.test_query.test_custom_AskHandler_correct","statement":"Path(test_custom_AskHandler(x), test_custom_AskHandler produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"e13949a02d06c382"}
def test_custom_AskHandler():
    from sympy.logic.boolalg import conjuncts

    # Old handler system
    class MersenneHandler(AskHandler):
        @staticmethod
        def Integer(expr, assumptions):
            if ask(Q.integer(log(expr + 1, 2))):
                return True
        @staticmethod
        def Symbol(expr, assumptions):
            if expr in conjuncts(assumptions):
                return True
    try:
        with warns_deprecated_sympy():
            register_handler('mersenne', MersenneHandler)
        n = Symbol('n', integer=True)
        with warns_deprecated_sympy():
            assert ask(Q.mersenne(7))
        with warns_deprecated_sympy():
            assert ask(Q.mersenne(n), Q.mersenne(n))
    finally:
        del Q.mersenne

    # New handler system
    class MersennePredicate(Predicate):
        pass
    try:
        Q.mersenne = MersennePredicate()
        @Q.mersenne.register(Integer)
        def _(expr, assumptions):
            if ask(Q.integer(log(expr + 1, 2))):
                return True
        @Q.mersenne.register(Symbol)
        def _(expr, assumptions):
            if expr in conjuncts(assumptions):
                return True
        assert ask(Q.mersenne(7))
        assert ask(Q.mersenne(n), Q.mersenne(n))
    finally:
        del Q.mersenne


