# @cctt_verify {"v":2,"sym":"sympy.assumptions.tests.test_query.test_polyadic_predicate","kind":"function","src_hash":"1783cdb98c753481","in":{"base":"Any"},"out":{"base":"Any","pred":"ask(Q.sexyprime(5, 11)) and ask(Q.sexyprime(7, 13, 19))"},"spec":{"lhs":"test_polyadic_predicate()","rhs":"test_polyadic_predicate produces the expected output","over":{"base":"Any"},"name":"test_polyadic_predicate_correct"},"guarantee":"test_polyadic_predicate produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.assumptions.tests.test_query.test_polyadic_predicate_correct","statement":"Path(test_polyadic_predicate(x), test_polyadic_predicate produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"e92a0b4cd5218152"}
def test_polyadic_predicate():

    class SexyPredicate(Predicate):
        pass
    try:
        Q.sexyprime = SexyPredicate()

        @Q.sexyprime.register(Integer, Integer)
        def _(int1, int2, assumptions):
            args = sorted([int1, int2])
            if not all(ask(Q.prime(a), assumptions) for a in args):
                return False
            return args[1] - args[0] == 6

        @Q.sexyprime.register(Integer, Integer, Integer)
        def _(int1, int2, int3, assumptions):
            args = sorted([int1, int2, int3])
            if not all(ask(Q.prime(a), assumptions) for a in args):
                return False
            return args[2] - args[1] == 6 and args[1] - args[0] == 6

        assert ask(Q.sexyprime(5, 11))
        assert ask(Q.sexyprime(7, 13, 19))
    finally:
        del Q.sexyprime


